import{_ as o,o as a,c as t,a3 as i}from"./chunks/framework.aYYe0dfI.js";const h=JSON.parse('{"title":"Module config:load","description":"The config:load module is responsible for deserializing and validating TOML configuration data, providing two public entry points: load_config for loading from a file path, and load_config_from_string for loading from an in‑memory string. Both return an integer status code that the caller must check to determine success. Internally, the module parses the TOML input, rejects unknown top‑level keys, and populates a RawTaskConfig intermediate representation before converting it into the schema types defined by the sibling config:schema module. Errors encountered during loading are captured as ConfigError objects, which carry a descriptive message string.","frontmatter":{"title":"Module config:load","description":"The config:load module is responsible for deserializing and validating TOML configuration data, providing two public entry points: load_config for loading from a file path, and load_config_from_string for loading from an in‑memory string. Both return an integer status code that the caller must check to determine success. Internally, the module parses the TOML input, rejects unknown top‑level keys, and populates a RawTaskConfig intermediate representation before converting it into the schema types defined by the sibling config:schema module. Errors encountered during loading are captured as ConfigError objects, which carry a descriptive message string.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/config/load.md","filePath":"en/clore/modules/config/load.md"}'),r={name:"clore/modules/config/load.md"};function n(c,e,d,l,s,f){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="module-config-load" tabindex="-1">Module <code>config:load</code> <a class="header-anchor" href="#module-config-load" aria-label="Permalink to &quot;Module `config:load`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>config:load</code> module is responsible for deserializing and validating TOML configuration data, providing two public entry points: <code>load_config</code> for loading from a file path, and <code>load_config_from_string</code> for loading from an in‑memory string. Both return an integer status code that the caller must check to determine success. Internally, the module parses the TOML input, rejects unknown top‑level keys, and populates a <code>RawTaskConfig</code> intermediate representation before converting it into the schema types defined by the sibling <code>config:schema</code> module. Errors encountered during loading are captured as <code>ConfigError</code> objects, which carry a descriptive message string.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./schema"><code>config:schema</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-config-configerror" tabindex="-1"><code>clore::config::ConfigError</code> <a class="header-anchor" href="#clore-config-configerror" aria-label="Permalink to &quot;`clore::config::ConfigError`&quot;">​</a></h3><p>Declaration: <code>config/load.cppm:15</code></p><p>Definition: <code>config/load.cppm:15</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p>The type <code>clore::config::ConfigError</code> is implemented as a simple value type holding a single <code>std::string</code> member <code>message</code>. There are no invariants beyond the usual string validity; the struct exists solely to bundle an error description in a dedicated type, enabling idiomatic error handling (e.g., via <code>std::expected</code> or exceptions) without exposing raw strings. No constructors, assignment <code>operator</code>s, or member functions are defined, making it a transparent wrapper that relies on default compiler-generated operations for copy, move, and comparison.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>message contains descriptive error text</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li>message</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>thrown or returned as an error from configuration operations</li><li>message is retrieved for logging or display</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-config-load-config" tabindex="-1"><code>clore::config::load_config</code> <a class="header-anchor" href="#clore-config-load-config" aria-label="Permalink to &quot;`clore::config::load_config`&quot;">​</a></h3><p>Declaration: <code>config/load.cppm:19</code></p><p>Definition: <code>config/load.cppm:81</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p>The implementation of <code>clore::config::load_config</code> begins by resolving the input <code>path</code> into an absolute, lexically normalized <code>config_path</code> using <code>std::filesystem</code>. If the file does not exist, it immediately returns a <code>ConfigError</code> with a descriptive message. Otherwise, it reads the file contents by calling <code>clore::support::read_utf8_text_file</code>. If reading fails, it returns another <code>ConfigError</code> carrying the underlying error string.</p><p>After obtaining the file content, the function delegates to <code>load_config_from_string</code> to parse the TOML and produce a <code>TaskConfig</code> value. On success, it sets the <code>workspace_root</code> member of the returned config to the parent directory of <code>config_path</code> (as a string). The entire flow uses early returns with <code>std::unexpected</code> for error propagation, relying on <code>ConfigError</code> as the common error type. No further validation or transformation is performed at this level; the heavy lifting occurs in <code>load_config_from_string</code>.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>reads from filesystem</li><li>allocates memory for file content</li><li>mutates returned <code>TaskConfig</code> object&#39;s <code>workspace_root</code> field</li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>file system at given <code>path</code></li><li>file content via <code>clore::support::read_utf8_text_file</code></li><li>result of <code>clore::config::load_config_from_string</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>return value of type <code>std::expected&lt;TaskConfig, ConfigError&gt;</code></li><li><code>.workspace_root</code> field of returned <code>TaskConfig</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>loading configuration from a file path</li><li>error handling with <code>std::expected</code> return type</li><li>setting workspace root automatically from config file location</li></ul><h3 id="clore-config-load-config-from-string" tabindex="-1"><code>clore::config::load_config_from_string</code> <a class="header-anchor" href="#clore-config-load-config-from-string" aria-label="Permalink to &quot;`clore::config::load_config_from_string`&quot;">​</a></h3><p>Declaration: <code>config/load.cppm:21</code></p><p>Definition: <code>config/load.cppm:110</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p>The implementation first normalizes the input by stripping a UTF-8 BOM via <code>clore::support::strip_utf8_bom</code>. It then parses the normalized string into a <code>::toml::table</code> using <code>::toml::parse</code>, catching <code>::toml::parse_error</code> and returning an unexpected <code>ConfigError</code> on failure. After parsing, it calls the local helper <code>reject_unknown_top_level_keys</code> to validate that no top-level keys outside the allowed set are present; if any are found, the function returns an error immediately.</p><p>Once the table passes validation, the function decodes its contents into a <code>RawTaskConfig</code> using <code>toml_codec::from_toml</code>. If decoding fails, it again produces an appropriate <code>ConfigError</code>. Finally, the raw configuration is transformed into the public <code>TaskConfig</code> type by invoking <code>to_config</code> on the moved <code>raw</code> object. The entire flow depends on the TOML parsing library, the custom validation and decoding helpers, and the conversion step that assembles the final configuration structure.</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>toml_content</code> parameter</li><li>global TOML parser state</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>returned <code>std::expected&lt;TaskConfig, ConfigError&gt;</code> object</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>loading configuration from a string</li><li>testing with inline TOML</li><li>processing embedded configuration</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>The <code>config:load</code> module is decomposed into a public API layer and an internal implementation hidden in an anonymous namespace. Two public entry points are provided: <code>load_config</code> for file‑based loading and <code>load_config_from_string</code> for direct string input; both return an <code>int</code> status code. Internally, the module defines a <code>RawTaskConfig</code> struct (with fields for LLM and filter settings) and a battery of helper functions—<code>to_config</code>, <code>reject_unknown_top_level_keys</code>—that handle TOML parsing, key validation, and conversion from the raw intermediate shape to the final configuration types imported from <code>config:schema</code>. The implementation relies on the <code>support</code> module for foundational utilities (file I/O, logging) and on <code>std</code> for standard library facilities, maintaining a clear separation between parsing, validation, and conversion stages.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./schema">Module config:schema</a></li><li><a href="./../support/">Module support</a></li></ul>',50)])])}const u=o(r,[["render",n]]);export{h as __pageData,u as default};
